import{_ as n,o as i,c as o,ag as t}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Bí Danh Python | Dotfiles (VI)","titleTemplate":":title","description":"Lệnh Python rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","frontmatter":{"title":"Bí Danh Python | Dotfiles","description":"Lệnh Python rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","lang":"vi-VN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Bí Danh Python | Dotfiles preview","canonical":"/vi/aliases/python/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Bí danh Python","pageType":"docs","schemaType":"WebPage","permalink":"/vi/aliases/python/"},"headers":[],"relativePath":"vi/aliases/python/index.md","filePath":"vi/aliases/python/index.md","lastUpdated":1773010926000}'),a={name:"vi/aliases/python/index.md"};function h(c,e,l,d,r,p){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="bi-danh-python" tabindex="-1">Bí Danh Python <a class="header-anchor" href="#bi-danh-python" aria-label="Permalink to &quot;Bí Danh Python&quot;">​</a></h1><p>Lệnh Python rút gọn.</p><p>Trang này giới thiệu một nhóm bí danh và các phím tắt lệnh thường dùng. Đọc trang này trước để hiểu quy ước đặt tên, đầu vào mong đợi và mẫu thực thi an toàn. Sau đó mở phụ lục tham khảo để xem toàn bộ danh sách lệnh và cú pháp chính xác. Các bí danh này giảm việc gõ lặp lại và duy trì hành vi quy trình làm việc nhất quán trên macOS, Linux và WSL.</p><h2 id="khi-nao-su-dung" tabindex="-1">Khi Nào Sử Dụng <a class="header-anchor" href="#khi-nao-su-dung" aria-label="Permalink to &quot;Khi Nào Sử Dụng&quot;">​</a></h2><p>Sử dụng trang này trước công việc shell hàng ngày khi bạn cần mẫu lệnh dự đoán được.</p><h2 id="bao-gom" tabindex="-1">Bao Gồm <a class="header-anchor" href="#bao-gom" aria-label="Permalink to &quot;Bao Gồm&quot;">​</a></h2><ul><li>Bí danh: 44</li><li>Hàm hỗ trợ: 2</li><li>Tệp nguồn: 1</li></ul><h2 id="vi-du-nhanh" tabindex="-1">Ví Dụ Nhanh <a class="header-anchor" href="#vi-du-nhanh" aria-label="Permalink to &quot;Ví Dụ Nhanh&quot;">​</a></h2><ul><li><code>black</code> → <code>&#39;python -m black&#39; # Định dạng mã với black</code></li><li><code>deact</code> → <code>&#39;deactivate&#39; # Hủy kích hoạt venv</code></li><li><code>ipy</code> → <code>&#39;ipython&#39; # Shell Python tương tác</code></li><li><code>lint</code> → <code>&#39;pylint&#39; # Kiểm tra mã</code></li><li><code>mkvenv</code> → <code>&#39;python -m venv .venv&#39; # Tạo .venv trong thư mục hiện tại</code></li><li><code>mkvenvlocal</code> → <code>&#39;python -m venv ./venv&#39; # Tạo ./venv trong thư mục hiện tại</code></li><li><code>mypy</code> → <code>&#39;python -m mypy&#39; # Kiểm tra kiểu tĩnh</code></li><li><code>pep8</code> → <code>&#39;autopep8&#39; # Định dạng mã</code></li><li><code>pipf</code> → <code>&#39;pip freeze&#39; # Hiện requirements đóng băng</code></li><li><code>pipi</code> → <code>&#39;pip install&#39; # Cài đặt gói</code></li><li><code>pipl</code> → <code>&#39;pip list&#39; # Liệt kê gói đã cài</code></li><li><code>pipout</code> → <code>&#39;pip freeze &gt; requirements.txt&#39; # Lưu requirements</code></li></ul><h2 id="buoc-tiep-theo" tabindex="-1">Bước Tiếp Theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước Tiếp Theo&quot;">​</a></h2><p>Mở danh sách đầy đủ:</p>',11)])])}const u=n(a,[["render",h]]);export{m as __pageData,u as default};
